from dataclasses import dataclass, field
from enum import StrEnum
from typing import Any
import uuid, datetime

class ReviewDecision(StrEnum):
    ACCEPT = "accept"   # approve as-is; commit to production
    EDIT   = "edit"     # approve with changes; agent revises and re-submits
    REJECT = "reject"   # do not proceed; discard the draft

@dataclass
class ReviewFeedback:
    decision:   ReviewDecision
    comments:   str = ''           # free-form notes explaining the decision
    edit_items: list[str] = field(default_factory=list)  # specific changes requested
    reviewer:   str = 'human'

@dataclass
class Draft:
    draft_id:   str
    task_id:    str
    content:    Any              # the actual output: str, dict, etc.
    version:    int = 1
    revision_of: str | None = None  # draft_id of the previous version
    feedback:   ReviewFeedback | None = None
    created_at: str = field(default_factory=lambda: datetime.datetime.utcnow().isoformat())

    @classmethod
    def create(cls, task_id: str, content: Any, version: int = 1, revision_of: str | None = None):
        return cls(
            draft_id=str(uuid.uuid4()),
            task_id=task_id,
            content=content,
            version=version,
            revision_of=revision_of,
        )

# In-memory store (use a database in production)
_drafts: dict[str, Draft] = {}
_review_events: dict[str, __import__('asyncio').Event] = {}

from fastapi import FastAPI
from fastapi.responses import JSONResponse

app = FastAPI()

@app.get('/draft/{draft_id}')
async def get_draft(draft_id: str):
    draft = _drafts.get(draft_id)
    if not draft:
        return JSONResponse({'error': 'not found'}, status_code=404)
    return JSONResponse({
        'draft_id':   draft.draft_id,
        'version':    draft.version,
        'content':    draft.content,
        'created_at': draft.created_at,
    })

@app.post('/review/{draft_id}')
async def submit_review(
    draft_id: str,
    decision: str,       # "accept" | "edit" | "reject"
    comments: str = '',
    edit_items: list[str] = None,
):
    draft = _drafts.get(draft_id)
    if not draft:
        return JSONResponse({'error': 'not found'}, status_code=404)

    draft.feedback = ReviewFeedback(
        decision=ReviewDecision(decision),
        comments=comments,
        edit_items=edit_items or [],
    )
    # Wake the waiting agent coroutine
    _review_events[draft_id].set()
    return JSONResponse({'status': 'review submitted'})

import difflib

def show_diff(old_content: str, new_content: str) -> str:
    lines_old = old_content.splitlines(keepends=True)
    lines_new = new_content.splitlines(keepends=True)
    diff = list(difflib.unified_diff(
        lines_old, lines_new,
        fromfile='v1 (previous)',
        tofile='v2 (revised)',
        lineterm='',
    ))
    return '\n'.join(diff)

def diff_drafts(prev_id: str, curr_id: str) -> str:
    prev = _drafts.get(prev_id)
    curr = _drafts.get(curr_id)
    if not (prev and curr):
        raise ValueError('draft not found')
    if not isinstance(prev.content, str) or not isinstance(curr.content, str):
        # For non-string content, fall back to JSON diff
        import json
        old_str = json.dumps(prev.content, indent=2)
        new_str = json.dumps(curr.content, indent=2)
        return show_diff(old_str, new_str)
    return show_diff(prev.content, curr.content)

# Example: render the diff to a reviewer before they submit feedback
# GET /diff/{current_draft_id}
@app.get('/diff/{draft_id}')
async def get_diff(draft_id: str):
    draft = _drafts.get(draft_id)
    if not draft or not draft.revision_of:
        return JSONResponse({'error': 'no previous version to diff'})
    diff = diff_drafts(draft.revision_of, draft_id)
    return JSONResponse({'diff': diff})

