# Revision prompt built from structured feedback:
def build_revision_prompt(feedback: ReviewFeedback) -> str:
    lines = ["Your draft requires the following changes:"]
    for item in feedback.edit_items:
        loc  = item.get("location", "unspecified location")
        issue = item["issue"]
        suggestion = item.get("suggestion", "")
        line = f"- [{loc}] {issue}"
        if suggestion:
            line += f". Suggested fix: {suggestion}"
        lines.append(line)
    if feedback.comments:
        lines.append(f"\nAdditional notes: {feedback.comments}")
    lines.append("\nPlease produce a revised draft addressing all of the above.")
    return "\n".join(lines)

# Checklist-driven review: attach evaluation criteria to each draft
from dataclasses import dataclass, field

@dataclass
class ChecklistItem:
    id:          str
    criterion:   str    # what to verify
    passed:      bool | None = None  # None = not yet evaluated
    comment:     str = ''

@dataclass
class ReviewChecklist:
    items: list[ChecklistItem] = field(default_factory=list)

    @property
    def all_passed(self) -> bool:
        return all(item.passed is True for item in self.items)

    @property
    def failed_items(self) -> list[ChecklistItem]:
        return [i for i in self.items if i.passed is False]

# Generate task-appropriate checklists
EMAIL_CHECKLIST = ReviewChecklist(items=[
    ChecklistItem('tone',       'Tone is appropriate for the recipient'),
    ChecklistItem('accuracy',   'All facts and figures are correct'),
    ChecklistItem('cta',        'Call-to-action is clear'),
    ChecklistItem('sensitive',  'No sensitive or confidential data included'),
    ChecklistItem('signature',  'Sender signature is correct'),
])

CODE_CHECKLIST = ReviewChecklist(items=[
    ChecklistItem('runs',       'Code runs without errors'),
    ChecklistItem('edge_cases', 'Edge cases are handled'),
    ChecklistItem('security',   'No obvious security issues (injection, secrets in code)'),
    ChecklistItem('tests',      'Tests exist and pass'),
])

def auto_reject_on_failed(checklist: ReviewChecklist) -> ReviewFeedback | None:
    """
    If critical items fail, automatically generate an edit request
    without requiring the human to manually write it.
    """
    failed = checklist.failed_items
    if not failed:
        return None
    return ReviewFeedback(
        decision=ReviewDecision.EDIT,
        edit_items=[
            f"{item.criterion}: {item.comment or 'see criterion'}"
            for item in failed
        ],
    )

import json, pathlib

TRAINING_LOG = pathlib.Path('review_training_data.jsonl')

def log_review_outcome(
    task:      str,
    draft:     Draft,
    feedback:  ReviewFeedback,
) -> None:
    """
    Append one training example per review cycle.
    Accepted drafts become positive examples;
    rejected/edited drafts + their feedback become correction examples.
    """
    entry = {
        'task':       task,
        'content':    draft.content,
        'version':    draft.version,
        'decision':   feedback.decision,
        'edit_items': feedback.edit_items,
        'comments':   feedback.comments,
    }
    with TRAINING_LOG.open('a') as f:
        f.write(json.dumps(entry) + '\n')

def summarise_rejection_patterns() -> dict[str, int]:
    """Count which edit_items appear most often — reveals systematic agent weaknesses."""
    counts: dict[str, int] = {}
    with TRAINING_LOG.open() as f:
        for line in f:
            entry = json.loads(line)
            if entry['decision'] in ('edit', 'reject'):
                for item in entry['edit_items']:
                    counts[item] = counts.get(item, 0) + 1
    return dict(sorted(counts.items(), key=lambda x: -x[1]))

